#!/usr/bin/env python3
"""
Setup automatique du MCP Organismes de Formation.
Lancez ce script dans votre dossier Organisme : python3 setup.py
Il cree tous les fichiers necessaires automatiquement.
"""
import base64, os

FILES = {
"server.py": """""",
"LISEZMOI.md": """""",
}

PLAIN_FILES = {
".gitignore": "data/\n__pycache__/\n*.pyc\n",
"requirements.txt": "mcp>=1.0.0\nhttpx>=0.27.0\n",
"install.bat": "@echo off\necho ================================================\necho   Installation - MCP Organismes de Formation\necho ================================================\necho.\npython --version >nul 2>&1\nif %errorlevel% neq 0 (\n    echo ERREUR : Python n est pas installe.\n    echo Telechargez-le : https://www.python.org/downloads/\n    pause\n    exit /b 1\n)\necho [1/2] Installation des dependances...\npip install -r requirements.txt\necho [2/2] Creation du dossier de donnees...\nif not exist \"data\" mkdir data\necho.\necho   Installation terminee !\npause\n",
"install.sh": "#!/bin/bash\necho \"================================================\"\necho \"  Installation - MCP Organismes de Formation\"\necho \"================================================\"\nif ! command -v python3 &> /dev/null; then\n    echo \"ERREUR : Python 3 n est pas installe.\"\n    exit 1\nfi\necho \"[1/2] Installation des dependances...\"\npip3 install -r requirements.txt\necho \"[2/2] Creation du dossier de donnees...\"\nmkdir -p data\necho \"  Installation terminee !\"\n",
}

print("=" * 50)
print("  Setup MCP Organismes de Formation")
print("=" * 50)
print()

for name, b64 in FILES.items():
    content = base64.b64decode(b64).decode("utf-8")
    with open(name, "w", encoding="utf-8", newline="\n") as f:
        f.write(content)
    print(f"  [OK] {name} ({len(content):,} octets)")

for name, content in PLAIN_FILES.items():
    with open(name, "w", encoding="utf-8", newline="\n") as f:
        f.write(content)
    print(f"  [OK] {name}")

os.makedirs("data", exist_ok=True)
print(f"  [OK] data/")

try:
    os.chmod("install.sh", 0o755)
except:
    pass

print()
print("Tous les fichiers sont en place !")
print()
print("Prochaines etapes :")
print("  1. pip install mcp httpx")
print("  2. Configurez Claude avec le chemin vers server.py")
print("     (voir LISEZMOI.md pour les details)")
print()
